SELECT leaning_id, COUNT(article_id) AS article_count
FROM article_leaning
GROUP BY leaning_id;

SELECT frequency 
FROM theme_frequency 
WHERE theme_id = 1;

SELECT author_name 
FROM authors 
WHERE author_id = (SELECT MAX(author_id) FROM authors);

SELECT theme_id
FROM theme_frequency
WHERE frequency = (SELECT MAX(frequency) FROM theme_frequency);

SELECT SUM(frequency) AS total_frequency
FROM theme_frequency
WHERE theme_id = 0;

SELECT COUNT(article_id) AS total_articles
FROM article_themes
WHERE theme_id = 0;

SELECT media_id, AVG(frequency) AS average_frequency
FROM theme_frequency
GROUP BY media_id;

SELECT leaning_id, COUNT(article_id) as article_count, AVG(leaning_confidence) as average_confidence, MAX(leaning_confidence) as max_confidence
FROM article_leaning
GROUP BY leaning_id;

SELECT theme_id, COUNT(article_id) AS total_articles
FROM article_themes
GROUP BY theme_id;
